INSERT INTO `dictionary` (`Type`,`Attribute`,`Vendor`,`RecommendedOP`,`RecommendedTable`,`RecommendedHelper`,`RecommendedTooltip`) VALUES
                         ('integer','Max-All-Session','dictionary.daloradius',':=','check',NULL,'Specifies the number of seconds in total (the counter never resets) for which the user may connect (very popular with prepaid accounts). Please notice that this attribute is internal to FreeRADIUS and is based on a respective sql module configuration in radiusd.conf'),
                         ('integer','Max-Daily-Session','dictionary.daloradius',':=','check',NULL,'Specifies the number of seconds (the counter resets daily) for which the user may connect each day (very popular with prepaid accounts). Please notice that this attribute is internal to FreeRADIUS and is based on a respective sql module configuration in radiusd.conf'),
                         ('integer','Max-Monthly-Session','dictionary.daloradius',':=','check',NULL,'Specifies the number of seconds (the counter resets monthly) for which the user may connect each month in total (very popular with prepaid accounts). Please notice that this attribute is internal to FreeRADIUS and is based on a respective sql module configuration in radiusd.conf'),
                         ('integer','Access-Period','dictionary.daloradius',':=','check',NULL,'Setting the number of seconds (e.g. X seconds) of this attribute for a user allows the user to log in only for the next X seconds specified. In other words, unlike Max-All-Session, this is NOT an attribute based on accumulated time, but rather a Time-To-Finish.'),
                         ('integer','Max-Weekly-Session','dictionary.daloradius',':=','check',NULL,'Specifies the number of seconds (the counter resets weekly) for which the user may connect each week (very popular with prepaid accounts). Please notice that this attribute is internal to FreeRADIUS and is based on a respective sql module configuration in radiusd.conf'),
                         ('integer','Max-Quaterly-Session','dictionary.daloradius',':=','check',NULL,'Specifies the number of seconds (the counter resets quarterly) for which the user may connect each quarter of a year (very popular with prepaid accounts). Please notice that this attribute is internal to FreeRADIUS and is based on a respective sql module configuration in radiusd.conf'),
                         ('integer','Max-Yearly-Session','dictionary.daloradius',':=','check',NULL,'Specifies the number of seconds (the counter resets yearly) for which the user may connect each year (very popular with prepaid accounts). Please notice that this attribute is internal to FreeRADIUS and is based on a respective sql module configuration in radiusd.conf'),
                         ('integer','CS-Total-Octets-Daily','dictionary.daloradius',':=','check','volumebytes','ChilliSpot Total Octets attribute for limiting the total (up/down) traffic of a user. The counter resets daily.'),
                         ('integer','CS-Total-Octets-Weekly','dictionary.daloradius',':=','check','volumebytes','ChilliSpot Total Octets attribute for limiting the total (up/down) traffic of a user. The counter resets weekly.'),
                         ('integer','CS-Total-Octets-Monthly','dictionary.daloradius',':=','check','volumebytes','ChilliSpot Total Octets attribute for limiting the total (up/down) traffic of a user. The counter resets monthly'),
                         ('integer','CS-Total-Octets-Quarterly','dictionary.daloradius',':=','check','volumebytes','ChilliSpot Total Octets attribute for limiting the total (up/down) traffic of a user. The counter resets quarterly.'),
                         ('integer','CS-Total-Octets-Yearly','dictionary.daloradius',':=','check','volumebytes','ChilliSpot Total Octets attribute for limiting the total (up/down) traffic of a user. The counter resets yearly.'),
                         ('integer','CS-Input-Octets-Yearly','dictionary.daloradius',':=','check','volumebytes','ChilliSpot Input Octets attribute for limiting the input traffic of a user. The counter resets yearly.'),
                         ('integer','CS-Input-Octets','dictionary.daloradius',':=','check','volumebytes','ChilliSpot Input Octets attribute for limiting the input traffic of a user. The counter never.'),
                         ('integer','CS-Input-Octets-Quarterly','dictionary.daloradius',':=','check','volumebytes','ChilliSpot Input Octets attribute for limiting the input traffic of a user. The counter resets quarterly.'),
                         ('integer','CS-Input-Octets-Weekly','dictionary.daloradius',':=','check','volumebytes','ChilliSpot Input Octets attribute for limiting the input traffic of a user. The counter resets weekly.'),
                         ('integer','CS-Input-Octets-Monthly','dictionary.daloradius',':=','check','volumebytes','ChilliSpot Input Octets attribute for limiting the input traffic of a user. The counter resets monthly.'),
                         ('integer','CS-Output-Octets-Yearly','dictionary.daloradius',':=','check','volumebytes','ChilliSpot Output Octets attribute for limiting the output traffic of a user. The counter resets yearly.'),
                         ('integer','CS-Output-Octets','dictionary.daloradius',':=','check','volumebytes','ChilliSpot Output Octets attribute for limiting the output traffic of a user. The counter never.'),
                         ('integer','CS-Output-Octets-Quarterly','dictionary.daloradius',':=','check','volumebytes','ChilliSpot Output Octets attribute for limiting the output traffic of a user. The counter resets quarterly.'),
                         ('integer','CS-Output-Octets-Monthly','dictionary.daloradius',':=','check','volumebytes','ChilliSpot Output Octets attribute for limiting the output traffic of a user. The counter resets monthly.'),
                         ('integer','CS-Output-Octets-Weekly','dictionary.daloradius',':=','check','volumebytes','ChilliSpot Output Octets attribute for limiting the output traffic of a user. The counter resets weekly.'),
                         ('integer','CS-Output-Octets-Daily','dictionary.daloradius',':=','check','volumebytes','ChilliSpot Output Octets attribute for limiting the output traffic of a user. The counter resets daily.'),
                         ('integer','CS-Input-Octets-Daily','dictionary.daloradius',':=','check','volumebytes','ChilliSpot Input Octets attribute for limiting the input traffic of a user. The counter resets daily.'),
                         ('integer','CS-Total-Octets','dictionary.daloradius',':=','check','volumebytes','ChilliSpot Total Octets attribute for limiting the total (up/down) traffic of a user. The counter never reset.');
